import { useEffect, useState } from "react";

function App() {

  const [homes, setHomes] = useState([]);

  useEffect(() => {

    const fetchEnergy = () => {
      fetch("http://localhost:5000/energy")
        .then((res) => res.json())
        .then((data) => {
          console.log(data);
          setHomes(data);
        });
    };

    fetchEnergy();

    const interval = setInterval(fetchEnergy, 3000);

    return () => clearInterval(interval);

  }, []);

  return (

    <div className="min-h-screen bg-black text-white p-8">

      <h1 className="text-5xl font-bold text-green-400 mb-10 text-center">
        OpenGreenGrid Dashboard
      </h1>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {homes.map((home, index) => (

          <div
            key={index}
            className="bg-gray-900 border border-green-500 rounded-2xl p-6 shadow-lg"
          >

            <h2 className="text-3xl font-semibold mb-4 text-green-300">
              {home.house}
            </h2>

            <p className="text-lg mb-2">
              ⚡ Generated Power:
              <span className="text-green-400 font-bold">
                {" "} {home.generatedPower} kWh
              </span>
            </p>

            <p className="text-lg mb-2">
              🔋 Consumed Power:
              <span className="text-yellow-400 font-bold">
                {" "} {home.consumedPower} kWh
              </span>
            </p>

            <p className="text-lg">
              🔌 Battery Level:
              <span className="text-blue-400 font-bold">
                {" "} {home.batteryLevel}%
              </span>
            </p>

          </div>

        ))}

      </div>

    </div>

  );

}

export default App;
